queries.sparql:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name ?variety WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasWines ?child ; p:hasVineyards ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  ?child p:variety ?variety .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Vineyards } }
  FILTER(?nf = ?total)
}

